def trimmed_mean(nums):
    if not nums:
        return None
    elif len(nums) == 1:
        return float(nums[0])
    else:
        nums.sort()
        min_occurrences = (len(nums) - 2) // 3
        max_occurrences = len(nums) - min_occurrences - 1
        return sum(nums[min_occurrences:max_occurrences]) / (max_occurrences - min_occurrences + 1)
